pred_sql:
SELECT "NCT", "Author", "Year", "Trial name", "Trial phase", "Cancer type", "Treatment regimen", "Control regimen", "Type of control", "Type of therapy", "Monotherapy/combination", "Type of combination" FROM clinical_trials WHERE "Trial phase" = 'Phase 3' AND "Cancer type" = 'Prostate' AND "Clincal setting in relation to surgery" IS NOT NULL AND (
  ("Type of control" = 'Radiation' AND ("Type of therapy" = 'Monotherapy' OR "Type of therapy" = 'Combination'))
  OR
  ("Type of therapy" = 'Combination' AND ("Type of combination" LIKE '%Chemo%' AND "Type of combination" LIKE '%Anti-EGFR%'))
) ;

